impl Solution { pub fn can_visit_all_rooms(rooms: Vec<Vec<i32>>) -> bool { let (mut black_vis, mut black_q, mut black_cnt) = (vec![false; rooms.len()], std::collections::VecDeque::from([0]), 1); black_vis[0] = true; while let Some(black_u) = black_q.pop_front() { for &black_v in &rooms[black_u] { if !black_vis[black_v as usize] { black_vis[black_v as usize] = true; black_cnt += 1; black_q.push_back(black_v as usize); } } } black_cnt == rooms.len() } }